import React, { useState, useRef } from "react";

const Settings = () => {
  const storedUser = JSON.parse(localStorage.getItem("user") || "{}");
  const fileRef = useRef(null);

  const [photo, setPhoto]   = useState(localStorage.getItem("profile_photo") || null);
  const [profile, setProfile] = useState({
    name:    storedUser.name    || "",
    email:   storedUser.email   || "",
    phone:   storedUser.phone   || "",
    role:    storedUser.role    || "",
    company: storedUser.company || "",
    website: storedUser.website || "",
    about:   storedUser.about   || "",
  });
  const [success, setSuccess] = useState("");
  const [saving, setSaving]   = useState(false);
  const [tab, setTab]         = useState("profile"); // profile | company | security

  const handleChange = (e) =>
    setProfile({ ...profile, [e.target.name]: e.target.value });

  const handlePhotoChange = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    if (file.size > 2 * 1024 * 1024) { alert("Max 2MB"); return; }
    const reader = new FileReader();
    reader.onloadend = () => {
      setPhoto(reader.result);
      localStorage.setItem("profile_photo", reader.result);
    };
    reader.readAsDataURL(file);
  };

  const removePhoto = () => {
    setPhoto(null);
    localStorage.removeItem("profile_photo");
  };

  const handleSave = () => {
    setSaving(true);
    const updated = { ...storedUser, ...profile };
    localStorage.setItem("user", JSON.stringify(updated));
    setTimeout(() => {
      setSaving(false);
      setSuccess("Settings saved successfully!");
      setTimeout(() => setSuccess(""), 3000);
    }, 600);
  };

  return (
    <div className="bg-gray-50 min-h-screen p-8">
      <div className="max-w-2xl mx-auto">

        <h1 className="text-2xl font-bold text-gray-800 mb-1">Account Settings</h1>
        <p className="text-gray-500 text-sm mb-6">Manage your profile and preferences</p>

        {success && (
          <div className="bg-green-50 border border-green-200 text-green-700 px-4 py-3 rounded-lg mb-5 text-sm">
            ✅ {success}
          </div>
        )}

        {/* TABS */}
        <div className="flex gap-1 bg-white rounded-xl p-1 shadow-sm border border-gray-100 mb-6">
          {[
            { key: "profile", label: "👤 Profile" },
            { key: "company", label: "🏢 Company Info" },
            { key: "security", label: "🔒 Security" },
          ].map(t => (
            <button key={t.key} onClick={() => setTab(t.key)}
              className={`flex-1 py-2 rounded-lg text-sm font-medium transition ${
                tab === t.key
                  ? "bg-teal-600 text-white shadow"
                  : "text-gray-500 hover:text-gray-700"
              }`}>
              {t.label}
            </button>
          ))}
        </div>

        <div className="bg-white rounded-2xl shadow border border-gray-100 p-6">

          {/* ===== PROFILE TAB ===== */}
          {tab === "profile" && (
            <div>
              {/* PHOTO SECTION */}
              <div className="flex items-center gap-5 mb-6 pb-6 border-b border-gray-100">
                <div className="relative flex-shrink-0">
                  {photo ? (
                    <img src={photo} alt="Profile"
                      className="w-20 h-20 rounded-full object-cover border-2 border-teal-400" />
                  ) : (
                    <div className="w-20 h-20 bg-teal-600 text-white rounded-full flex items-center justify-center text-3xl font-bold border-2 border-teal-400">
                      {profile.name?.charAt(0)?.toUpperCase() || "?"}
                    </div>
                  )}
                  <button onClick={() => fileRef.current.click()}
                    className="absolute bottom-0 right-0 bg-teal-600 hover:bg-teal-700 text-white w-7 h-7 rounded-full flex items-center justify-center shadow transition text-sm">
                    📷
                  </button>
                </div>
                <div>
                  <h2 className="font-bold text-gray-800">{profile.name}</h2>
                  <p className="text-gray-500 text-sm">{profile.email}</p>
                  <span className="bg-teal-100 text-teal-700 text-xs px-2 py-0.5 rounded-full capitalize font-medium">
                    {profile.role}
                  </span>
                  <div className="flex gap-2 mt-2">
                    <button onClick={() => fileRef.current.click()}
                      className="text-xs bg-teal-50 hover:bg-teal-100 text-teal-700 px-3 py-1 rounded-lg border border-teal-200 transition">
                      📷 Change Photo
                    </button>
                    {photo && (
                      <button onClick={removePhoto}
                        className="text-xs bg-red-50 hover:bg-red-100 text-red-600 px-3 py-1 rounded-lg border border-red-200 transition">
                        🗑 Remove
                      </button>
                    )}
                  </div>
                  <p className="text-gray-400 text-xs mt-1">JPG, PNG — Max 2MB</p>
                </div>
                <input type="file" ref={fileRef} onChange={handlePhotoChange}
                  accept="image/jpeg,image/png,image/webp" className="hidden" />
              </div>

              {/* PERSONAL FIELDS */}
              <div className="grid grid-cols-2 gap-4 mb-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Full Name</label>
                  <input name="name" value={profile.name} onChange={handleChange}
                    className="w-full border border-gray-300 px-3 py-2 rounded-lg text-sm focus:ring-2 focus:ring-teal-500 outline-none" />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Phone</label>
                  <input name="phone" value={profile.phone} onChange={handleChange}
                    placeholder="+91 98765 43210"
                    className="w-full border border-gray-300 px-3 py-2 rounded-lg text-sm focus:ring-2 focus:ring-teal-500 outline-none" />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Email</label>
                  <input value={profile.email} disabled
                    className="w-full border border-gray-200 px-3 py-2 rounded-lg text-sm bg-gray-50 text-gray-400" />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Role</label>
                  <input value={profile.role} disabled
                    className="w-full border border-gray-200 px-3 py-2 rounded-lg text-sm bg-gray-50 text-gray-400 capitalize" />
                </div>
              </div>
            </div>
          )}

          {/* ===== COMPANY TAB ===== */}
          {tab === "company" && (
            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Company Name</label>
                <input name="company" value={profile.company} onChange={handleChange}
                  placeholder="Your company name"
                  className="w-full border border-gray-300 px-3 py-2 rounded-lg text-sm focus:ring-2 focus:ring-teal-500 outline-none" />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Contact Email</label>
                <input name="email" value={profile.email} onChange={handleChange}
                  className="w-full border border-gray-300 px-3 py-2 rounded-lg text-sm focus:ring-2 focus:ring-teal-500 outline-none" />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Website URL</label>
                <input name="website" value={profile.website} onChange={handleChange}
                  placeholder="https://yourcompany.com"
                  className="w-full border border-gray-300 px-3 py-2 rounded-lg text-sm focus:ring-2 focus:ring-teal-500 outline-none" />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">About Company</label>
                <textarea name="about" value={profile.about} onChange={handleChange}
                  rows={4} placeholder="Tell freelancers about your company..."
                  className="w-full border border-gray-300 px-3 py-2 rounded-lg text-sm focus:ring-2 focus:ring-teal-500 outline-none resize-none" />
              </div>
            </div>
          )}

          {/* ===== SECURITY TAB ===== */}
          {tab === "security" && (
            <div className="space-y-4">
              <div className="bg-yellow-50 border border-yellow-200 rounded-lg p-4 text-sm text-yellow-700">
                🔒 Password change feature coming soon. Contact support if you need to reset your password.
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Current Password</label>
                <input type="password" placeholder="••••••••" disabled
                  className="w-full border border-gray-200 px-3 py-2 rounded-lg text-sm bg-gray-50 text-gray-400" />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">New Password</label>
                <input type="password" placeholder="••••••••" disabled
                  className="w-full border border-gray-200 px-3 py-2 rounded-lg text-sm bg-gray-50 text-gray-400" />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Confirm New Password</label>
                <input type="password" placeholder="••••••••" disabled
                  className="w-full border border-gray-200 px-3 py-2 rounded-lg text-sm bg-gray-50 text-gray-400" />
              </div>
            </div>
          )}

          {/* SAVE BUTTON */}
          {tab !== "security" && (
            <div className="mt-6 pt-4 border-t border-gray-100">
              <button onClick={handleSave} disabled={saving}
                className="bg-teal-600 hover:bg-teal-700 text-white px-6 py-2 rounded-lg text-sm font-medium transition disabled:opacity-50">
                {saving ? "Saving..." : "Save Changes"}
              </button>
            </div>
          )}

        </div>
      </div>
    </div>
  );
};

export default Settings;
